import { AnimatePresence, motion } from 'framer-motion'
import { ArrowLeft, CheckCircle2, Circle, Filter, Loader2, Package, RefreshCw, XCircle } from 'lucide-react'
import React, { useEffect, useState } from 'react'
import { useToast } from '../hooks/useToast'
import { vendasService } from '../services/api'
import { Venda } from '../types/api'

interface GridComandasProps {
  onClose: () => void
  onEditarComanda: (nota: string) => void
}

type FiltroStatus = 'todas' | 'abertas' | 'fechadas'

const GridComandas: React.FC<GridComandasProps> = ({ onClose, onEditarComanda }) => {
  const [vendas, setVendas] = useState<Venda[]>([])
  const [vendasAbertas, setVendasAbertas] = useState<Venda[]>([])
  const [vendasFiltradas, setVendasFiltradas] = useState<Venda[]>([])
  const [isLoading, setIsLoading] = useState(false)
  const [filtroStatus, setFiltroStatus] = useState<FiltroStatus>('abertas')
  const [comandasUnicas, setComandasUnicas] = useState<Map<number, Venda>>(new Map())
  const { showError, showSuccess } = useToast()

  useEffect(() => {
    carregarVendas()
  }, [])

  useEffect(() => {
    aplicarFiltro()
  }, [filtroStatus, vendas, vendasAbertas, comandasUnicas])

  const carregarVendas = async () => {
    setIsLoading(true)
    try {
      // Buscar todas as vendas de hoje e as abertas em paralelo
      const [vendasHoje, vendasAbertasData] = await Promise.all([
        vendasService.getHoje(),
        vendasService.getAbertas()
      ])
      
      setVendas(vendasHoje)
      setVendasAbertas(vendasAbertasData)

      // Criar mapa de comandas únicas (pegar a mais recente de cada comanda)
      // Primeiro adicionar todas as vendas de hoje
      const mapaComandas = new Map<number, Venda>()
      vendasHoje.forEach(venda => {
        if (venda.comanda) {
          const comandaExistente = mapaComandas.get(venda.comanda)
          if (!comandaExistente || new Date(venda.emissao) > new Date(comandaExistente.emissao)) {
            mapaComandas.set(venda.comanda, venda)
          }
        }
      })
      
      // Depois adicionar/atualizar com as comandas abertas (prioridade para abertas)
      vendasAbertasData.forEach(venda => {
        if (venda.comanda) {
          const comandaExistente = mapaComandas.get(venda.comanda)
          // Se não existe ou se a venda aberta é mais recente, usar a venda aberta
          if (!comandaExistente || new Date(venda.emissao) >= new Date(comandaExistente.emissao)) {
            mapaComandas.set(venda.comanda, venda)
          }
        }
      })
      
      setComandasUnicas(mapaComandas)
    } catch (error: any) {
      console.error('Erro ao carregar vendas:', error)
      showError('Erro', 'Não foi possível carregar as comandas')
    } finally {
      setIsLoading(false)
    }
  }

  const aplicarFiltro = () => {
    const todasComandas = Array.from(comandasUnicas.values()).filter(v => v.comanda)
    const comandasAbertasSet = new Set(vendasAbertas.map(v => v.comanda).filter(Boolean))

    let filtradas: Venda[]

    if (filtroStatus === 'todas') {
      filtradas = todasComandas
    } else if (filtroStatus === 'abertas') {
      // Para comandas abertas, usar diretamente as vendas abertas (mais confiável)
      // Mas também incluir qualquer comanda do mapa que esteja aberta
      const comandasAbertasDoMapa = todasComandas.filter(v => 
        v.comanda && comandasAbertasSet.has(v.comanda)
      )
      
      // Combinar com as vendas abertas diretas (pode haver diferenças)
      const todasAbertas = [...vendasAbertas]
      comandasAbertasDoMapa.forEach(venda => {
        if (!todasAbertas.find(v => v.comanda === venda.comanda)) {
          todasAbertas.push(venda)
        }
      })
      
      // Remover duplicatas mantendo a mais recente
      const mapaAbertas = new Map<number, Venda>()
      todasAbertas.forEach(v => {
        if (v.comanda) {
          const existente = mapaAbertas.get(v.comanda)
          if (!existente || new Date(v.emissao) > new Date(existente.emissao)) {
            mapaAbertas.set(v.comanda, v)
          }
        }
      })
      
      filtradas = Array.from(mapaAbertas.values())
    } else {
      // Fechadas: todas que não estão abertas
      filtradas = todasComandas.filter(v => 
        v.comanda && !comandasAbertasSet.has(v.comanda)
      )
    }

    setVendasFiltradas(filtradas)
  }


  const handleComandaClick = async (venda: Venda) => {
    if (!venda.comanda) return

    // Verificar se está aberta usando o set já carregado
    const comandasAbertasSet = new Set(vendasAbertas.map(v => v.comanda).filter(Boolean))
    const estaAberta = comandasAbertasSet.has(venda.comanda)
    
    if (estaAberta) {
      // Buscar a venda aberta atual
      try {
        const vendaAberta = vendasAbertas.find(v => v.comanda === venda.comanda)
        
        if (vendaAberta) {
          onEditarComanda(vendaAberta.nota)
          onClose()
        } else {
          // Se não encontrou na lista atual, buscar novamente
          const vendasAbertasAtualizadas = await vendasService.getAbertas()
          const vendaAbertaAtualizada = vendasAbertasAtualizadas.find(v => v.comanda === venda.comanda)
          
          if (vendaAbertaAtualizada) {
            onEditarComanda(vendaAbertaAtualizada.nota)
            onClose()
          } else {
            showError('Aviso', 'Comanda não encontrada como aberta')
          }
        }
      } catch (error) {
        showError('Erro', 'Não foi possível abrir a comanda para edição')
      }
    } else {
      showError('Aviso', 'Esta comanda está fechada e não pode ser editada')
    }
  }

  const formatarPreco = (valor: number) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL'
    }).format(valor)
  }

  // Obter comandas para exibir baseado no filtro
  const comandasParaExibir = vendasFiltradas
    .filter(v => v.comanda)
    .sort((a, b) => (a.comanda || 0) - (b.comanda || 0))

  // Criar set de comandas abertas para verificação rápida
  const comandasAbertasSet = new Set(vendasAbertas.map(v => v.comanda).filter(Boolean))

  // Criar grid de comandas (4 por linha)
  // Para o modo "abertas" ou "fechadas", mostrar apenas as comandas filtradas
  // Para o modo "todas", mostrar um grid completo até a maior comanda
  let gridFiltrado: (Venda | null)[][] = []
  
  if (filtroStatus === 'todas') {
    // Modo "todas": criar grid completo até a maior comanda
    const todasComandas = Array.from(comandasUnicas.values()).filter(v => v.comanda)
    const maxComanda = todasComandas.length > 0 
      ? Math.max(...todasComandas.map(v => v.comanda || 0))
      : 20 // Default para 20 se não houver comandas
    
    const numLinhas = Math.ceil(maxComanda / 4)
    
    for (let i = 0; i < numLinhas; i++) {
      const linha: (Venda | null)[] = []
      for (let j = 0; j < 4; j++) {
        const numComanda = i * 4 + j + 1
        const venda = todasComandas.find(v => v.comanda === numComanda)
        linha.push(venda || null)
      }
      gridFiltrado.push(linha)
    }
  } else {
    // Modo "abertas" ou "fechadas": mostrar apenas as comandas filtradas em grid
    const numLinhas = Math.ceil(comandasParaExibir.length / 4)
    
    for (let i = 0; i < numLinhas; i++) {
      const linha: (Venda | null)[] = []
      for (let j = 0; j < 4; j++) {
        const index = i * 4 + j
        if (index < comandasParaExibir.length) {
          linha.push(comandasParaExibir[index])
        } else {
          linha.push(null)
        }
      }
      // Só adicionar linha se tiver pelo menos uma comanda
      if (linha.some(c => c !== null)) {
        gridFiltrado.push(linha)
      }
    }
  }

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <div className="bg-primary text-primary-foreground p-4 sm:p-6 sticky top-0 z-50 shadow-lg">
        <div className="flex items-center justify-between">
          <button
            onClick={onClose}
            className="flex items-center space-x-2 hover:bg-white/20 rounded-xl p-2 transition-colors"
          >
            <ArrowLeft className="w-5 h-5" />
            <span className="font-semibold hidden sm:inline">Voltar</span>
          </button>

          <h1 className="text-xl sm:text-2xl font-bold text-center flex-1">Comandas</h1>

          <div className="flex items-center space-x-2">
            <button
              onClick={carregarVendas}
              disabled={isLoading}
              className="p-2 hover:bg-white/20 rounded-xl transition-colors disabled:opacity-50"
              title="Atualizar"
            >
              <RefreshCw className={`w-5 h-5 ${isLoading ? 'animate-spin' : ''}`} />
            </button>
          </div>
        </div>

        {/* Filtros */}
        <div className="mt-4 flex flex-wrap gap-2 justify-center">
          <button
            onClick={() => setFiltroStatus('todas')}
            className={`px-4 py-2 rounded-xl font-semibold transition-all ${
              filtroStatus === 'todas'
                ? 'bg-white text-primary shadow-lg'
                : 'bg-white/20 text-white hover:bg-white/30'
            }`}
          >
            <Filter className="w-4 h-4 inline mr-2" />
            Todas
          </button>
          <button
            onClick={() => setFiltroStatus('abertas')}
            className={`px-4 py-2 rounded-xl font-semibold transition-all ${
              filtroStatus === 'abertas'
                ? 'bg-white text-primary shadow-lg'
                : 'bg-white/20 text-white hover:bg-white/30'
            }`}
          >
            <Circle className="w-4 h-4 inline mr-2" />
            Abertas
          </button>
          <button
            onClick={() => setFiltroStatus('fechadas')}
            className={`px-4 py-2 rounded-xl font-semibold transition-all ${
              filtroStatus === 'fechadas'
                ? 'bg-white text-primary shadow-lg'
                : 'bg-white/20 text-white hover:bg-white/30'
            }`}
          >
            <XCircle className="w-4 h-4 inline mr-2" />
            Fechadas
          </button>
        </div>
      </div>

      {/* Content */}
      <div className="p-4 sm:p-6">
        {isLoading && vendas.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 space-y-4">
            <Loader2 className="w-12 h-12 text-primary animate-spin" />
            <p className="text-lg text-text-secondary">Carregando comandas...</p>
          </div>
        ) : gridFiltrado.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 space-y-4">
            <Package className="w-16 h-16 text-text-muted" />
            <p className="text-lg font-semibold text-text-primary">
              {filtroStatus === 'abertas' 
                ? 'Nenhuma comanda aberta' 
                : filtroStatus === 'fechadas'
                ? 'Nenhuma comanda fechada'
                : 'Nenhuma comanda encontrada'}
            </p>
            <p className="text-sm text-text-secondary">
              {filtroStatus === 'abertas' 
                ? 'Todas as comandas foram finalizadas' 
                : 'Não há comandas para exibir'}
            </p>
          </div>
        ) : (
          <div className="max-w-4xl mx-auto">
            {/* Grid de Comandas */}
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 sm:gap-4">
              {gridFiltrado.flat().map((venda, index) => {
                if (!venda) {
                  // Célula vazia (apenas no modo "todas")
                  if (filtroStatus === 'todas') {
                    return (
                      <div
                        key={`empty-${index}`}
                        className="aspect-square bg-card-secondary border-2 border-dashed border-border rounded-2xl flex items-center justify-center opacity-30"
                      >
                        <span className="text-text-muted text-sm font-semibold">-</span>
                      </div>
                    )
                  }
                  // No modo "abertas" ou "fechadas", não mostrar células vazias
                  return null
                }

                const numComanda = venda.comanda || 0
                const isAberta = comandasAbertasSet.has(numComanda)

                return (
                  <motion.button
                    key={venda.nota}
                    initial={{ scale: 0.9, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    whileHover={{ scale: 1.05 }}
                    whileTap={{ scale: 0.95 }}
                    onClick={() => handleComandaClick(venda)}
                    disabled={!isAberta && filtroStatus === 'abertas'}
                    className={`aspect-square rounded-2xl p-3 sm:p-4 flex flex-col items-center justify-between transition-all shadow-lg ${
                      isAberta || filtroStatus !== 'abertas'
                        ? filtroStatus === 'abertas'
                          ? 'bg-red-500 text-white hover:bg-red-600 cursor-pointer'
                          : filtroStatus === 'fechadas'
                          ? 'bg-green-500 text-white hover:bg-green-600 cursor-pointer'
                          : isAberta
                          ? 'bg-red-500 text-white hover:bg-red-600 cursor-pointer'
                          : 'bg-green-500 text-white hover:bg-green-600 cursor-pointer'
                        : 'bg-gray-300 text-gray-600 cursor-not-allowed opacity-50'
                    }`}
                  >
                    <div className="flex items-center justify-between w-full">
                      {isAberta || filtroStatus !== 'abertas' ? (
                        filtroStatus === 'abertas' || isAberta ? (
                          <Circle className="w-4 h-4 sm:w-5 sm:h-5" />
                        ) : (
                          <CheckCircle2 className="w-4 h-4 sm:w-5 sm:h-5" />
                        )
                      ) : null}
                      <span className="text-xs sm:text-sm font-bold">
                        #{numComanda.toString().padStart(3, '0')}
                      </span>
                    </div>

                    <div className="text-center flex-1 flex flex-col justify-center">
                      <p className="text-xs sm:text-sm font-semibold mb-1">
                        {venda.mesa ? `Mesa ${venda.mesa}` : 'Comanda'}
                      </p>
                      {venda.numeroPessoas && (
                        <p className="text-xs opacity-90">
                          {venda.numeroPessoas} {venda.numeroPessoas === 1 ? 'pessoa' : 'pessoas'}
                        </p>
                      )}
                    </div>

                    <div className="text-center w-full">
                      <p className="text-xs sm:text-sm font-bold">
                        {formatarPreco(venda.total || 0)}
                      </p>
                      {isAberta && filtroStatus === 'abertas' && (
                        <p className="text-xs opacity-90 mt-1">Toque para editar</p>
                      )}
                    </div>
                  </motion.button>
                )
              })}
            </div>

            {/* Resumo */}
            <div className="mt-6 bg-card rounded-2xl p-4 shadow-lg border border-border">
              <div className="flex flex-wrap justify-between items-center gap-4 text-sm">
                <div>
                  <span className="text-text-secondary">Total de comandas: </span>
                  <span className="font-bold text-text-primary">{comandasParaExibir.length}</span>
                </div>
                <div>
                  <span className="text-text-secondary">Valor total: </span>
                  <span className="font-bold text-primary">
                    {formatarPreco(
                      comandasParaExibir.reduce((acc, v) => acc + (v.total || 0), 0)
                    )}
                  </span>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

export default GridComandas

