import axios from 'axios';

// Detectar automaticamente a URL da API baseado no host atual
const getApiUrl = () => {
  // Se estiver em desenvolvimento (localhost), usar localhost
  if (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1') {
    return 'http://localhost:65375/api';
  }
  
  // Caso contrário, usar o mesmo host e porta 65375
  const hostname = window.location.hostname;
  return `http://${hostname}:65375/api`;
};

const API_URL = getApiUrl();

export interface ItemConferencia {
  codigo: number;
  descricao: string;
  qtd: number;
  precoUnitario: number;
  total: number;
}

export interface ClienteConferencia {
  id: number;
  nome: string;
  cpfCnpj?: string;
  telefone?: string;
}

export interface ConferenciaMesa {
  nota: string;
  mesa: number | null;
  comanda: number | null;
  garcom: string | null;
  dataHora: string;
  itens: ItemConferencia[];
  subtotal: number;
  desconto: number;
  acrescimo: number;
  total: number;
  totalItens: number;
  cliente?: ClienteConferencia;
}

export const conferenciaService = {
  async getConferenciaMesa(mesa: number): Promise<ConferenciaMesa> {
    const response = await axios.get(`${API_URL}/vendas/conferencia/mesa/${mesa}`);
    return response.data;
  },

  async getConferenciaComanda(comanda: number): Promise<ConferenciaMesa> {
    const response = await axios.get(`${API_URL}/vendas/conferencia/comanda/${comanda}`);
    return response.data;
  }
};

