import { 
  ClipboardList, 
  FileText, 
  LayoutGrid,
  LogOut, 
  Receipt, 
  Search, 
  ShoppingBag,
  TrendingUp
} from 'lucide-react'
import React from 'react'
import { Button } from './ui/button'

interface MenuPrincipalProps {
  onNovaComanda: () => void
  onBuscarEditar: () => void
  onVerComandasAbertas: () => void
  onGerarExtrato: () => void
  onTotalComandasAbertas: () => void
  onPesquisarProdutos: () => void
  onGridComandas: () => void
  onSair: () => void
  totalComandasAbertas?: number
  totalValorAberto?: number
}

const MenuPrincipal: React.FC<MenuPrincipalProps> = ({
  onNovaComanda,
  onBuscarEditar,
  onVerComandasAbertas,
  onGerarExtrato,
  onTotalComandasAbertas,
  onPesquisarProdutos,
  onGridComandas,
  onSair,
  totalComandasAbertas = 0,
  totalValorAberto = 0
}) => {
  return (
    <div className="min-h-screen bg-background p-6">
      <div className="max-w-md mx-auto space-y-4">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold bg-gradient-to-r from-primary to-primary-700 bg-clip-text text-transparent mb-2">
            iComanda
          </h1>
          <p className="text-sm text-text-muted">Menu Principal</p>
        </div>

        {/* Total de Comandas Abertas - Clicável */}
        <div 
          onClick={onTotalComandasAbertas}
          className="bg-gradient-to-r from-primary/20 via-primary/10 to-accent/20 border-2 border-primary/30 rounded-3xl p-6 cursor-pointer hover:border-primary/50 transition-all duration-300 hover:scale-[1.02] active:scale-[0.98]"
        >
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center space-x-3">
              <div className="w-12 h-12 bg-primary/20 rounded-2xl flex items-center justify-center">
                <TrendingUp className="w-6 h-6 text-primary" />
              </div>
              <div>
                <p className="text-sm font-medium text-text-secondary">Comandas em Aberto</p>
                <p className="text-2xl font-bold text-text-primary">{totalComandasAbertas}</p>
              </div>
            </div>
            <div className="text-right">
              <p className="text-sm font-medium text-text-secondary">Valor Total</p>
              <p className="text-xl font-bold text-primary">
                R$ {totalValorAberto.toFixed(2).replace('.', ',')}
              </p>
            </div>
          </div>
          <p className="text-xs text-text-muted text-center">
            Toque para ver detalhes
          </p>
        </div>

        {/* Botões Principais */}
        <div className="grid grid-cols-2 gap-4">
          {/* Nova Comanda */}
          <Button
            onClick={onNovaComanda}
            className="h-32 flex flex-col items-center justify-center space-y-3 bg-primary hover:bg-primary/90 text-primary-foreground rounded-2xl shadow-lg hover:shadow-xl transition-all duration-300 hover:scale-105 active:scale-95"
          >
            <ClipboardList className="w-8 h-8" />
            <span className="font-semibold text-base">Nova Comanda</span>
          </Button>

          {/* Buscar/Editar */}
          <Button
            onClick={onBuscarEditar}
            variant="outline"
            className="h-32 flex flex-col items-center justify-center space-y-3 border-2 border-border hover:border-primary/50 bg-card hover:bg-card-hover rounded-2xl shadow-lg hover:shadow-xl transition-all duration-300 hover:scale-105 active:scale-95"
          >
            <Receipt className="w-8 h-8 text-primary" />
            <span className="font-semibold text-base text-text-primary">Buscar/Editar</span>
          </Button>

          {/* Ver Comandas Abertas */}
          <Button
            onClick={onVerComandasAbertas}
            variant="outline"
            className="h-32 flex flex-col items-center justify-center space-y-3 border-2 border-border hover:border-primary/50 bg-card hover:bg-card-hover rounded-2xl shadow-lg hover:shadow-xl transition-all duration-300 hover:scale-105 active:scale-95"
          >
            <ShoppingBag className="w-8 h-8 text-primary" />
            <span className="font-semibold text-base text-text-primary">Comandas Abertas</span>
          </Button>

          {/* Gerar Extrato */}
          <Button
            onClick={onGerarExtrato}
            variant="outline"
            className="h-32 flex flex-col items-center justify-center space-y-3 border-2 border-border hover:border-primary/50 bg-card hover:bg-card-hover rounded-2xl shadow-lg hover:shadow-xl transition-all duration-300 hover:scale-105 active:scale-95"
          >
            <FileText className="w-8 h-8 text-primary" />
            <span className="font-semibold text-base text-text-primary">Gerar Extrato</span>
          </Button>

          {/* Grid de Comandas */}
          <Button
            onClick={onGridComandas}
            variant="outline"
            className="h-32 flex flex-col items-center justify-center space-y-3 border-2 border-border hover:border-primary/50 bg-card hover:bg-card-hover rounded-2xl shadow-lg hover:shadow-xl transition-all duration-300 hover:scale-105 active:scale-95"
          >
            <LayoutGrid className="w-8 h-8 text-primary" />
            <span className="font-semibold text-base text-text-primary">Grid de Comandas</span>
          </Button>
        </div>

        {/* Botões Secundários */}
        <div className="space-y-3 mt-6">
          {/* Pesquisar Produtos */}
          <Button
            onClick={onPesquisarProdutos}
            variant="outline"
            className="w-full h-14 flex items-center justify-center space-x-3 border-2 border-border hover:border-primary/50 bg-card hover:bg-card-hover rounded-2xl shadow-lg hover:shadow-xl transition-all duration-300"
          >
            <Search className="w-5 h-5 text-primary" />
            <span className="font-semibold text-base text-text-primary">Pesquisar Produtos</span>
          </Button>

          {/* Sair */}
          <Button
            onClick={onSair}
            variant="outline"
            className="w-full h-14 flex items-center justify-center space-x-3 border-2 border-red-200 hover:border-red-300 bg-red-50 hover:bg-red-100 text-red-600 rounded-2xl shadow-lg hover:shadow-xl transition-all duration-300"
          >
            <LogOut className="w-5 h-5" />
            <span className="font-semibold text-base">Sair</span>
          </Button>
        </div>
      </div>
    </div>
  )
}

export default MenuPrincipal

