import axios from 'axios';
import { BuscarProdutoRequest, Cliente, CriarVendaRequest, Grupo, Produto, Venda } from '../types/api';

// Detectar automaticamente a URL da API baseado no host atual
const getApiBaseUrl = () => {
  // Se estiver em desenvolvimento (localhost), usar localhost
  if (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1') {
    return 'http://localhost:65375/api';
  }
  
  // Caso contrário, usar o mesmo host e porta 65375
  // Ex: se acessar por http://192.168.0.22:3000, a API será http://192.168.0.22:65375/api
  const hostname = window.location.hostname;
  return `http://${hostname}:65375/api`;
};

const API_BASE_URL = getApiBaseUrl();

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Interceptor para logar erros nas requisições
api.interceptors.request.use(
  (config) => {
    return config;
  },
  (error) => {
    console.error('❌ [Axios] Erro na requisição:', error);
    return Promise.reject(error);
  }
);

// Interceptor para logar erros nas respostas
api.interceptors.response.use(
  (response) => {
    return response;
  },
  (error) => {
    console.error(`❌ [Axios] Erro na resposta: ${error.config?.url}`);
    console.error(`❌ [Axios] Status: ${error.response?.status}`);
    console.error(`❌ [Axios] Dados do erro:`, error.response?.data);
    return Promise.reject(error);
  }
);

// Serviços para Grupos
export const gruposService = {
  getAll: async (): Promise<Grupo[]> => {
    const response = await api.get('/grupos');
    return response.data;
  },

  getTodosComQuantidade: async (): Promise<Grupo[]> => {
    try {
      const response = await api.get('/grupos/todos-com-quantidade');
      return response.data;
    } catch (error: any) {
      console.error('❌ [gruposService] Erro ao buscar grupos:', error?.message || error);
      throw error;
    }
  },

  getById: async (id: number): Promise<Grupo> => {
    const response = await api.get(`/grupos/${id}`);
    return response.data;
  },
};

// Serviços para Produtos
